3920 bool ICmpInst::isImpliedFalseByMatchingCmp(CmpPredicate Pred1,
3921                                            CmpPredicate Pred2) {
3922   return isImpliedTrueByMatchingCmp(Pred1, getInversePredicate(Pred2));
3923 }
